-- Facility Manager — schema + dữ liệu mẫu (users, RBAC menu, phòng, tài sản, …).
-- Import: mysql -u root -p --default-character-set=utf8mb4 < database/mysql/schema.sql
-- TKB (tùy chọn): mysql -u root -p --default-character-set=utf8mb4 < database/mysql/seed_tkb.sql

DROP DATABASE IF EXISTS asset_management;
CREATE DATABASE asset_management
  CHARACTER SET utf8mb4
  COLLATE utf8mb4_unicode_ci;

USE asset_management;

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- Bảng: users
CREATE TABLE `users` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `username` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `password_hash` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `full_name` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `address` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone_number` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `role` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ACTIVE',
  `avatar_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_users_username` (`username`),
  KEY `idx_users_role` (`role`)
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Mật khẩu demo: 123456 (trừ hieutruong: ******). Đăng nhập bằng cột username.

-- Bảng: categories
CREATE TABLE `categories` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_categories_code` (`code`)
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Bảng: rooms
CREATE TABLE `rooms` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `room_code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `building_code` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `floor` int NOT NULL,
  `class_using` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `department` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `capacity` int NOT NULL,
  `status` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `teacher_name` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `class_studying` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `desk_count` int NOT NULL DEFAULT '0',
  `chair_count` int NOT NULL DEFAULT '0',
  `speaker_count` int NOT NULL DEFAULT '0',
  `air_conditioner_count` int NOT NULL DEFAULT '0',
  `microphone_count` int NOT NULL DEFAULT '0',
  `glass_door_status` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ceiling_fan_count` int NOT NULL DEFAULT '0',
  `curtain_status` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_rooms_room_code` (`room_code`),
  KEY `idx_rooms_building_code` (`building_code`)
) ENGINE=InnoDB AUTO_INCREMENT=87 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Bảng: assets
CREATE TABLE `assets` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `card_number` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `asset_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `provider` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `country` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `department` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `classroom` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `asset_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `item_category` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `item_category_id` bigint unsigned DEFAULT NULL,
  `manufacture_year` int DEFAULT NULL,
  `unit_price` decimal(18,2) DEFAULT NULL,
  `quantity` int NOT NULL DEFAULT '0',
  `original_price` decimal(18,2) DEFAULT NULL,
  `fund_source` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fund_source_id` bigint unsigned DEFAULT NULL,
  `usage_time` int DEFAULT NULL,
  `purchase_date` date DEFAULT NULL,
  `usage_year` int DEFAULT NULL,
  `buyer_user_id` bigint unsigned DEFAULT NULL,
  `room_id` bigint unsigned DEFAULT NULL,
  `status` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'IN_USE',
  `note` text COLLATE utf8mb4_unicode_ci,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_assets_card_number` (`card_number`),
  KEY `idx_assets_status` (`status`),
  KEY `idx_assets_item_category` (`item_category`),
  KEY `idx_assets_item_category_id` (`item_category_id`),
  KEY `idx_assets_fund_source_id` (`fund_source_id`),
  KEY `fk_assets_buyer_user_id` (`buyer_user_id`),
  KEY `fk_assets_room_id` (`room_id`),
  CONSTRAINT `fk_assets_item_category_id` FOREIGN KEY (`item_category_id`) REFERENCES `categories` (`id`),
  CONSTRAINT `fk_assets_fund_source_id` FOREIGN KEY (`fund_source_id`) REFERENCES `categories` (`id`),
  CONSTRAINT `fk_assets_buyer_user_id` FOREIGN KEY (`buyer_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_assets_room_id` FOREIGN KEY (`room_id`) REFERENCES `rooms` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=410 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



-- Bảng: requests
CREATE TABLE `requests` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `note` varchar(1000) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `manager_group` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `priority` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `manager_name` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `attachment_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'NEW',
  `is_draft` tinyint(1) NOT NULL DEFAULT '0',
  `created_by_user_id` bigint unsigned DEFAULT NULL,
  `assigned_to_user_id` bigint unsigned DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_requests_status` (`status`),
  KEY `idx_requests_created_by_user_id` (`created_by_user_id`),
  KEY `idx_requests_assigned_to_user_id` (`assigned_to_user_id`),
  CONSTRAINT `fk_requests_created_by_user_id` FOREIGN KEY (`created_by_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_requests_assigned_to_user_id` FOREIGN KEY (`assigned_to_user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- NEW (không nháp): manager_name và assigned_to_user_id = NULL. Đã xử lý: gán assigned_to_user_id theo users.id.

-- Bảng: audits (kiểm kê định kỳ)
CREATE TABLE `audits` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `scope_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'BUILDING|ROOM',
  `scope_value` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'IN_PROGRESS' COMMENT 'DRAFT|IN_PROGRESS|COMPLETED',
  `created_by` bigint unsigned DEFAULT NULL,
  `started_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `completed_at` datetime DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_audits_status` (`status`),
  KEY `idx_audits_scope` (`scope_type`,`scope_value`),
  CONSTRAINT `fk_audits_created_by` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `audit_details` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `audit_id` bigint unsigned NOT NULL,
  `asset_id` bigint unsigned DEFAULT NULL,
  `card_number` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `asset_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  `system_qty` int NOT NULL DEFAULT '0',
  `system_room` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `system_status` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `actual_qty` int DEFAULT NULL,
  `actual_room` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `actual_status` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `note` text COLLATE utf8mb4_unicode_ci,
  `matched` tinyint(1) NOT NULL DEFAULT '0',
  `discrepancy_type` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'THIEU|SAI_VI_TRI|HONG|KHAC',
  `room_floor` int DEFAULT NULL,
  `room_code` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_audit_details_audit` (`audit_id`),
  KEY `idx_audit_details_sort` (`audit_id`,`room_floor`,`room_code`),
  CONSTRAINT `fk_audit_details_audit` FOREIGN KEY (`audit_id`) REFERENCES `audits` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_audit_details_asset` FOREIGN KEY (`asset_id`) REFERENCES `assets` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Bảng: room_usage_slots (dùng cho lọc lịch theo ngày/ca ở trang phòng học)
CREATE TABLE IF NOT EXISTS `room_usage_slots` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `room_code` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL,
  `weekday` int NOT NULL COMMENT '2..7 tương ứng Thứ 2..Thứ 7',
  `shift` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'MORNING/AFTERNOON/EVENING',
  `period_label` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `period_start` int DEFAULT NULL,
  `period_end` int DEFAULT NULL,
  `usage_label` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `owner_unit` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `primary_contact` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `assistant_contact` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `semester` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `valid_from` date DEFAULT NULL,
  `valid_to` date DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_room_usage_slots_room` (`room_code`),
  KEY `idx_room_usage_slots_semester` (`semester`),
  KEY `idx_room_usage_slots_weekday` (`weekday`),
  KEY `idx_room_usage_slots_shift` (`shift`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Lịch học (room_usage_slots): seed qua seed_tkb.sql (Docker init 02).

-- Bảng: asset_transfers
CREATE TABLE `asset_transfers` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `asset_id` bigint unsigned NOT NULL,
  `source_building` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `source_classroom` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `giver_user_id` bigint unsigned DEFAULT NULL,
  `receiver_user_id` bigint unsigned DEFAULT NULL,
  `target_building` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `target_classroom` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `received_date` date DEFAULT NULL,
  `note` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_asset_transfers_asset_id` (`asset_id`),
  KEY `idx_asset_transfers_received_date` (`received_date`),
  KEY `fk_asset_transfers_giver_user_id` (`giver_user_id`),
  KEY `fk_asset_transfers_receiver_user_id` (`receiver_user_id`),
  CONSTRAINT `fk_asset_transfers_asset_id` FOREIGN KEY (`asset_id`) REFERENCES `assets` (`id`),
  CONSTRAINT `fk_asset_transfers_giver_user_id` FOREIGN KEY (`giver_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_asset_transfers_receiver_user_id` FOREIGN KEY (`receiver_user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Không seed: lịch sử điều chuyển ghi qua POST /api/assets/{id}/transfer

SET FOREIGN_KEY_CHECKS = 1;


-- RBAC tables and demo seed used by the current backend build.
USE asset_management;

CREATE TABLE IF NOT EXISTS fm_menu_permissions (
  id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
  parent_id BIGINT UNSIGNED DEFAULT NULL,
  title VARCHAR(200) NOT NULL,
  menu_name VARCHAR(120) NOT NULL,
  path VARCHAR(500) DEFAULT NULL,
  permission_type INT NOT NULL DEFAULT 0 COMMENT '-1=NAV, 0=PAGE',
  sort_order INT NOT NULL DEFAULT 0,
  PRIMARY KEY (id),
  KEY idx_fm_menu_parent (parent_id),
  CONSTRAINT fk_fm_menu_parent FOREIGN KEY (parent_id) REFERENCES fm_menu_permissions (id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS fm_roles (
  id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
  code VARCHAR(50) NOT NULL,
  name VARCHAR(150) NOT NULL,
  description VARCHAR(500) DEFAULT NULL,
  sort_order INT NOT NULL DEFAULT 0,
  parent_role_id BIGINT UNSIGNED DEFAULT NULL,
  created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (id),
  UNIQUE KEY uk_fm_roles_code (code),
  KEY idx_fm_roles_parent (parent_role_id),
  CONSTRAINT fk_fm_roles_parent FOREIGN KEY (parent_role_id) REFERENCES fm_roles (id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS fm_role_menu (
  role_id BIGINT UNSIGNED NOT NULL,
  menu_id BIGINT UNSIGNED NOT NULL,
  PRIMARY KEY (role_id, menu_id),
  CONSTRAINT fk_fm_role_menu_role FOREIGN KEY (role_id) REFERENCES fm_roles (id) ON DELETE CASCADE,
  CONSTRAINT fk_fm_role_menu_menu FOREIGN KEY (menu_id) REFERENCES fm_menu_permissions (id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



-- RBAC1 seed: gán menu nền cho STAFF, MANAGER kế thừa STAFF,
-- ADMIN chỉ cần gán phần mở rộng ngoài quyền nền.

