INSERT INTO `requests` (`id`, `title`, `note`, `manager_group`, `priority`, `manager_name`, `attachment_url`, `status`, `is_draft`, `created_by_user_id`, `assigned_to_user_id`, `created_at`, `updated_at`) VALUES
(1, 'Yêu cầu sửa chữa máy lạnh phòng P303C2', 'Máy lạnh tại phòng P303C2 bị hỏng máy nén - không làm lạnh được. Đề nghị kiểm tra và sửa chữa gấp.', 'CSVC', 'HIGH', NULL, NULL, 'NEW', 0, 1, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(2, 'Yêu cầu cấp máy tính cho phòng 301DN', 'Phòng máy tính 301DN hiện có 10 máy hỏng cần thay thế. Đề nghị cấp bổ sung 10 máy tính mới.', 'CNTT', 'HIGH', 'Bùi Thị Hồng Nhung', NULL, 'IN_PROGRESS', 0, 7, 7, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(3, 'Yêu cầu thay bóng đèn hành lang tòa C2', 'Hệ thống đèn hành lang tầng 2 và tầng 3 tòa C2 bị hỏng nhiều bóng. Đề nghị thay thế toàn bộ.', 'CSVC', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'RESOLVED', 0, 4, 2, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(4, 'Yêu cầu bổ sung bàn ghế phòng 504DN', 'Phòng 504DN hiện thiếu 10 bộ bàn ghế do số lượng sinh viên tăng. Đề nghị bổ sung sớm.', 'CSVC', 'NORMAL', 'Hoàng Văn Bình', NULL, 'DRAFT', 1, 8, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(5, 'Yêu cầu sửa chữa máy chiếu phòng P404C2', 'Máy chiếu tại phòng P404C2 bị lỗi không hiển thị hình ảnh. Giảng viên phản ánh ảnh hưởng đến giảng dạy.', 'CNTT', 'HIGH', NULL, NULL, 'NEW', 0, 7, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(6, 'Yêu cầu vệ sinh điều hòa các phòng tòa E7', 'Điều hòa các phòng tòa E7 chưa được vệ sinh trong học kỳ này. Đề nghị lên kế hoạch vệ sinh định kỳ.', 'CSVC', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'IN_PROGRESS', 0, 4, 2, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(7, 'Yêu cầu sửa chữa bảng trắng phòng P302C2', 'Bảng trắng phòng P302C2 bị bong lớp phủ không thể xóa sạch. Đề nghị thay mới hoặc phủ lại bề mặt.', 'CSVC', 'LOW', 'Trần Thị Lan Anh', NULL, 'RESOLVED', 0, 4, 2, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(8, 'Yêu cầu cấp phát dụng cụ cho phòng thực hành cơ khí', 'Phòng thực hành P301C2 thiếu bộ dụng cụ cơ bản cho sinh viên thực hành. Đề nghị cấp bổ sung theo danh sách đính kèm.', 'THIET_BI', 'HIGH', 'Nguyễn Đức Thắng', NULL, 'DRAFT', 1, 6, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(9, 'Yêu cầu sửa chữa hệ thống loa phòng 401DN', 'Loa phòng 401DN phát ra tiếng rè không rõ. Ảnh hưởng đến chất lượng nghe giảng của sinh viên.', 'CSVC', 'NORMAL', NULL, NULL, 'NEW', 0, 9, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(10, 'Yêu cầu nâng cấp mạng LAN phòng P1E6', 'Hạ tầng mạng P1E6 cũ kỹ, tốc độ chậm. Đề nghị nâng cấp hệ thống switch và dây cáp mạng.', 'CNTT', 'HIGH', 'Bùi Thị Hồng Nhung', NULL, 'IN_PROGRESS', 0, 7, 7, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(11, 'Yêu cầu thay kính cửa phòng P501C2', 'Kính cửa phòng P501C2 bị nứt vỡ do va đập. Đề nghị thay thế để đảm bảo an toàn.', 'CSVC', 'HIGH', 'Đặng Thị Thu Hằng', NULL, 'RESOLVED', 0, 4, 9, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(12, 'Yêu cầu bảo trì máy móc phòng thực hành ô tô', 'Thiết bị tại P2E5 và P504C2 cần được bảo dưỡng định kỳ trước đầu học kỳ mới.', 'THIET_BI', 'NORMAL', 'Phan Minh Khoa', NULL, 'DRAFT', 1, 10, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(13, 'Yêu cầu sửa chữa toilet tầng 2 tòa C2', 'Toilet tầng 2 tòa C2 có 2 bồn cầu hỏng và hệ thống xả nước không hoạt động. Đề nghị sửa chữa gấp.', 'CSVC', 'HIGH', NULL, NULL, 'NEW', 0, 4, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(14, 'Yêu cầu cấp mực in cho văn phòng khoa', 'Văn phòng Khoa Công nghệ Thông tin hết mực in. Đề nghị cấp bổ sung 5 hộp mực HP.', 'CNTT', 'NORMAL', 'Bùi Thị Hồng Nhung', NULL, 'IN_PROGRESS', 0, 7, 7, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(15, 'Yêu cầu sửa chữa rèm cửa phòng 201DN', 'Rèm cửa phòng 201DN bị đứt dây kéo, không điều chỉnh được. Ảnh hưởng đến ánh sáng phòng học.', 'CSVC', 'LOW', 'Trần Thị Lan Anh', NULL, 'RESOLVED', 0, 4, 2, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(16, 'Yêu cầu lắp đặt camera an ninh khu vực thực hành', 'Khu vực thực hành cơ khí và phòng thực hành ô tô chưa có camera giám sát. Đề nghị lắp đặt để đảm bảo an ninh.', 'CSVC', 'NORMAL', 'Nguyễn Minh Tuấn', NULL, 'DRAFT', 1, 1, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(17, 'Yêu cầu sửa chữa thang máy tòa E7', 'Thang máy tòa E7 thường xuyên bị lỗi, dừng giữa chừng. Đề nghị bảo trì khẩn cấp.', 'CSVC', 'HIGH', NULL, NULL, 'NEW', 0, 4, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(18, 'Yêu cầu cấp thiết bị bảo hộ cho sinh viên thực hành', 'Sinh viên thực hành tại phòng thực hành thiếu kính bảo hộ và găng tay. Đề nghị cấp đủ số lượng.', 'THIET_BI', 'HIGH', 'Nguyễn Đức Thắng', NULL, 'IN_PROGRESS', 0, 6, 6, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(19, 'Yêu cầu sơn lại phòng học P201C2', 'Phòng P201C2 tường bị ố vàng, bong tróc sơn. Đề nghị sơn lại trước khai giảng năm học mới.', 'CSVC', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'RESOLVED', 0, 4, 2, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(20, 'Yêu cầu thay thế máy tính hỏng phòng P1E4', '3 máy tính trong phòng P1E4 không khởi động được. Đề nghị sửa chữa hoặc thay thế mới.', 'CNTT', 'NORMAL', 'Đặng Thị Thu Hằng', NULL, 'DRAFT', 1, 9, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(21, 'Yêu cầu bảo trì hệ thống điện phòng thực hành P102E7', 'Hệ thống điện phòng thực hành P102E7 xuất hiện sự cố chập chờn. Cần kiểm tra và bảo trì ngay.', 'THIET_BI', 'HIGH', NULL, NULL, 'NEW', 0, 9, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(22, 'Yêu cầu cấp bảng vẽ kỹ thuật phòng P5E8', 'Phòng vẽ P5E8 thiếu 5 bảng vẽ kỹ thuật cho sinh viên. Đề nghị bổ sung trước tuần 3 của học kỳ.', 'THIET_BI', 'NORMAL', 'Hoàng Văn Bình', NULL, 'IN_PROGRESS', 0, 8, 8, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(23, 'Yêu cầu sửa chữa hệ thống chiếu sáng phòng thực hành', 'Đèn tại P301C2 và P1E3 bị hỏng một số bóng. Ảnh hưởng đến an toàn khi thực hành.', 'CSVC', 'HIGH', 'Nguyễn Đức Thắng', NULL, 'RESOLVED', 0, 6, 6, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(24, 'Yêu cầu thanh lý tài sản hỏng học kỳ I/2024', 'Danh sách tài sản hỏng không sửa được cần được lập hồ sơ thanh lý theo quy định. Đính kèm danh sách.', 'THIET_BI', 'NORMAL', 'Nguyễn Minh Tuấn', NULL, 'DRAFT', 1, 1, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(25, 'Yêu cầu cấp mô hình học cụ cho Khoa Ô tô', 'Khoa Kỹ thuật Ô tô cần bổ sung mô hình động cơ mới phục vụ đào tạo học kỳ II.', 'THIET_BI', 'HIGH', NULL, NULL, 'NEW', 0, 10, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(26, 'Yêu cầu sửa chữa cửa phòng P3E6', 'Cửa phòng P3E6 bị hỏng bản lề, không đóng kín. Ảnh hưởng đến bảo mật thiết bị trong phòng.', 'CSVC', 'NORMAL', 'Hoàng Văn Bình', NULL, 'IN_PROGRESS', 0, 8, 8, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(27, 'Yêu cầu vệ sinh máy tính phòng 301DN', 'Máy tính phòng 301DN bụi bẩn, cần vệ sinh định kỳ để đảm bảo tuổi thọ thiết bị.', 'CNTT', 'LOW', 'Bùi Thị Hồng Nhung', NULL, 'RESOLVED', 0, 7, 7, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(28, 'Yêu cầu lắp thêm ổ cắm điện phòng P3E4', 'Phòng P3E4 thiếu ổ cắm điện cho sinh viên sạc thiết bị trong giờ thực hành. Đề nghị lắp bổ sung.', 'CSVC', 'NORMAL', 'Đặng Thị Thu Hằng', NULL, 'DRAFT', 1, 9, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(29, 'Yêu cầu sửa chữa hàng rào khu vực thực hành', 'Hàng rào khu vực thực hành có đoạn bị gãy đổ. Cần sửa chữa để đảm bảo an toàn và bảo vệ tài sản.', 'CSVC', 'HIGH', NULL, NULL, 'NEW', 0, 4, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(30, 'Yêu cầu nâng cấp phần mềm máy tính P1E6', 'Phần mềm chuyên ngành trên máy tính P1E6 đã cũ cần cập nhật phiên bản mới.', 'CNTT', 'NORMAL', 'Bùi Thị Hồng Nhung', NULL, 'IN_PROGRESS', 0, 7, 7, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(31, 'Yêu cầu sửa chữa máy chiếu phòng P2E4', 'Máy chiếu phòng P2E4 không lấy nét được, hình ảnh bị mờ. Cần sửa chữa trước khi giảng dạy học kỳ mới.', 'THIET_BI', 'NORMAL', 'Nguyễn Đức Thắng', NULL, 'RESOLVED', 0, 6, 6, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(32, 'Yêu cầu cấp dụng cụ vệ sinh cho các phòng học', 'Các phòng học tòa C2 và tòa E7 thiếu dụng cụ vệ sinh cơ bản. Đề nghị cấp bổ sung theo số phòng.', 'CSVC', 'LOW', 'Trần Thị Lan Anh', NULL, 'DRAFT', 1, 4, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(33, 'Yêu cầu kiểm tra và bảo dưỡng máy bơm nước', 'Hệ thống máy bơm nước tòa E5 hoạt động không ổn định. Cần kiểm tra và bảo dưỡng định kỳ.', 'CSVC', 'HIGH', NULL, NULL, 'NEW', 0, 4, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(34, 'Yêu cầu cấp bổ sung ghế cho hội trường', 'Hội trường thiếu 30 ghế cho các sự kiện lớn của trường. Đề nghị mua bổ sung hoặc mượn từ kho.', 'CSVC', 'NORMAL', 'Nguyễn Minh Tuấn', NULL, 'IN_PROGRESS', 0, 1, 1, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(35, 'Yêu cầu sửa chữa loa treo tường phòng 404DN', 'Loa phòng 404DN phát ra tiếng lạch cạch, âm thanh không rõ. Ảnh hưởng đến chất lượng giảng dạy.', 'THIET_BI', 'NORMAL', 'Đặng Thị Thu Hằng', NULL, 'RESOLVED', 0, 9, 9, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(36, 'Yêu cầu cấp thiết bị đo lường cho P3E5', 'Phòng thực hành P3E5 thiếu đồng hồ vạn năng và thiết bị đo lường điện cho sinh viên thực hành.', 'THIET_BI', 'HIGH', 'Đặng Thị Thu Hằng', NULL, 'DRAFT', 1, 9, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(37, 'Yêu cầu sửa chữa ổ khóa văn phòng khoa CK', 'Ổ khóa văn phòng Khoa Cơ khí bị hỏng không mở được. Đề nghị thay khóa mới ngay.', 'CSVC', 'HIGH', NULL, NULL, 'NEW', 0, 6, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(38, 'Yêu cầu vệ sinh bể nước mái tòa C2', 'Bể nước mái tòa C2 chưa được vệ sinh trong 6 tháng. Đề nghị vệ sinh định kỳ theo quy định.', 'CSVC', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'IN_PROGRESS', 0, 4, 2, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(39, 'Yêu cầu sửa chữa bộ mô phỏng ô tô P2E5', 'Bộ mô phỏng ô tô số 1 tại P2E5 bị lỗi phần mềm, không khởi động được. Đề nghị liên hệ nhà cung cấp sửa chữa.', 'THIET_BI', 'HIGH', 'Phan Minh Khoa', NULL, 'RESOLVED', 0, 10, 10, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(40, 'Yêu cầu trang bị biển số phòng mới tòa E9', 'Tòa E9 mới chưa có biển số phòng. Đề nghị làm biển số đồng bộ với các tòa còn lại.', 'CSVC', 'LOW', 'Trần Thị Lan Anh', NULL, 'DRAFT', 1, 4, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(41, 'Yêu cầu cấp máy in cho văn phòng Khoa XD', 'Máy in văn phòng Khoa Xây dựng bị hỏng không sửa được. Đề nghị mua thay thế mới.', 'CNTT', 'NORMAL', NULL, NULL, 'NEW', 0, 8, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(42, 'Yêu cầu sửa chữa mô hình động cơ diesel P301C2', 'Mô hình động cơ diesel tại P301C2 bị hỏng hệ thống nhiên liệu. Cần sửa chữa trước học kỳ II.', 'THIET_BI', 'HIGH', 'Nguyễn Đức Thắng', NULL, 'IN_PROGRESS', 0, 6, 6, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(43, 'Yêu cầu lắp đặt wifi cho phòng 203DN', 'Phòng 203DN chưa có wifi nên sinh viên không thể học trực tuyến. Đề nghị lắp đặt access point.', 'CNTT', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'RESOLVED', 0, 4, 2, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(44, 'Yêu cầu cấp bổ sung bàn vẽ kỹ thuật', 'Phòng vẽ P2E3 thiếu 5 bàn vẽ kỹ thuật cho sinh viên năm nhất Khoa Xây dựng. Đề nghị cấp gấp.', 'THIET_BI', 'HIGH', 'Hoàng Văn Bình', NULL, 'DRAFT', 1, 8, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(45, 'Yêu cầu thay thế switch mạng P4E5', 'Switch mạng phòng P4E5 bị lỗi, không ổn định. Đề nghị thay thế để đảm bảo kết nối mạng.', 'CNTT', 'HIGH', NULL, NULL, 'NEW', 0, 5, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(46, 'Yêu cầu sơn kẻ đường đi trong khuôn viên', 'Đường đi bộ và kẻ vạch đỗ xe trong khuôn viên bị mờ. Đề nghị kẻ lại để đảm bảo an toàn.', 'CSVC', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'IN_PROGRESS', 0, 4, 2, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(47, 'Yêu cầu sửa chữa màn chiếu điện phòng P3E4', 'Màn chiếu điện phòng P3E4 bị hỏng motor, không cuộn lên được. Đề nghị sửa chữa hoặc thay mới.', 'THIET_BI', 'NORMAL', 'Đặng Thị Thu Hằng', NULL, 'RESOLVED', 0, 9, 9, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(48, 'Yêu cầu kiểm tra hệ thống PCCC toàn trường', 'Hệ thống phòng cháy chữa cháy cần được kiểm tra định kỳ 6 tháng/lần. Đề nghị lên kế hoạch kiểm tra.', 'CSVC', 'HIGH', 'Nguyễn Minh Tuấn', NULL, 'DRAFT', 1, 1, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(49, 'Yêu cầu cấp bổ sung ghế xoay cho P1E3', 'Phòng thực hành P1E3 thiếu 8 ghế xoay cho sinh viên ngồi thực hành lý thuyết tại chỗ.', 'THIET_BI', 'NORMAL', NULL, NULL, 'NEW', 0, 6, NULL, '2026-05-12 14:31:56', '2026-05-12 14:31:56'),
(50, 'Yêu cầu sửa chữa hệ thống chiếu sáng sân trường', 'Một số đèn chiếu sáng sân trường bị hỏng, gây mất an toàn vào ban đêm. Đề nghị thay thế gấp.', 'CSVC', 'HIGH', 'Trần Thị Lan Anh', NULL, 'IN_PROGRESS', 0, 4, 2, '2026-05-12 14:31:56', '2026-05-12 14:31:56');
